using UnityEngine;

/// <summary>
/// Agarrar/carregar/atirar objectos (Babuíno "puxa/arremessa sem dano para
/// reposicionar", Gibão, ovo da galinha — P6). Usa o botão de INTERAGIR
/// (não há botão de agarrar dedicado — correcção P4):
///
/// - Agarrar: SEGURAR Interagir encostado a um Carryable (forma com
///   'canGrab' e peso ≤ maxCarryWeight) agarra-o automaticamente — não é
///   preciso "apertar", basta tocar enquanto o botão está premido. O objecto
///   fica preso enquanto Interagir continuar premido.
/// - Largar (correcção): SOLTAR Interagir larga o objecto com física baseada
///   no movimento nesse instante (ver <see cref="Drop"/>) — a correr "atira"
///   o objecto com o momentum do player; segurando para CIMA o objecto sobe
///   mais; parado + para cima é só jogado para cima; parado sem input cai à
///   frente sem velocidade (comportamento antigo).
/// - Atirar (forçado): o botão de ATAQUE, enquanto carrega, atira o objecto
///   com força fixa (se a forma tiver 'canThrow'; senão usa Drop). O
///   arremesso em si não causa dano — objectos como o ovo (EggObject) é que
///   causam dano próprio no impacto.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class GrabThrowAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Agarrar")]
    [Tooltip("Alcance à frente do player para detectar um Carryable.")]
    public float grabRange = 1.2f;

    [Tooltip("Peso máximo (ObjectWeight) que esta forma carrega. Objectos mais pesados não são agarráveis.")]
    public float maxCarryWeight = 3f;

    [Tooltip("Ponto onde o objecto carregado fica preso (auto-criado acima da cabeça se vazio).")]
    public Transform carryAnchor;

    [Header("Largar (ao soltar Interagir)")]
    [Tooltip("Quanto de Move.y (0..1) é preciso para contar como 'a apontar para cima' ao largar.")]
    [Range(0.1f, 1f)] public float releaseUpThreshold = 0.4f;

    [Tooltip("Velocidade horizontal mínima do player (m/s) para contar como 'a correr' ao largar.")]
    public float runningSpeedThreshold = 0.5f;

    [Tooltip("Impulso vertical extra somado à velocidade do player ao largar segurando para cima (a correr).")]
    public float releaseUpBoost = 4f;

    [Tooltip("Impulso vertical do objecto quando largado parado + a segurar para cima (jogado só para cima).")]
    public float verticalTossForce = 6f;

    [Header("Atirar (botão de Ataque, força fixa)")]
    [Tooltip("Velocidade horizontal do arremesso forçado.")]
    public float throwForce = 8f;

    [Tooltip("Componente vertical do arremesso forçado.")]
    public float throwUpForce = 4f;

    [Header("Input")]
    [Tooltip("Auto-preenchido.")]
    [SerializeField] private PlayerInputRouter input;

    [Tooltip("Auto-preenchido — não agarra objectos enquanto está a escalar (Interagir já está ocupado a segurar a superfície).")]
    [SerializeField] private ClimbAbility climb;

    [Tooltip("Auto-preenchido — não agarra objectos enquanto está a balançar num cipó (P8).")]
    [SerializeField] private SwingAbility swing;

    private PlayerMotor2D motor;
    private AnimalFormData form;
    private bool canGrab;

    // Buffer NonAlloc reutilizável — evita alocação por frame em TryGrab.
    private static readonly Collider2D[] _grabBuffer = new Collider2D[8];
    private bool canThrow;

    private Carryable _carried;

    /// <summary>true enquanto está a carregar um objecto.</summary>
    public bool IsCarrying => _carried != null;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();

        if (input == null) input = GetComponent<PlayerInputRouter>();
        if (climb == null) climb = GetComponent<ClimbAbility>();
        if (swing == null) swing = GetComponent<SwingAbility>();

        if (carryAnchor == null)
        {
            var anchor = new GameObject("CarryAnchor");
            anchor.transform.SetParent(transform);
            anchor.transform.localPosition = new Vector3(0f, 1.1f, 0f);
            carryAnchor = anchor.transform;
        }
    }

    private void OnEnable()
    {
        if (input != null) input.InteractReleased += HandleInteractReleased;
    }

    private void OnDisable()
    {
        if (input != null) input.InteractReleased -= HandleInteractReleased;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        canGrab = form != null && form.canGrab;
        canThrow = form != null && form.canThrow;

        // Trocar de forma larga o objecto (a nova forma pode não conseguir
        // carregá-lo). Neutro (DropNeutral) — transformar a meio de uma
        // corrida não deve arremessar o objecto com o momentum do player.
        if (IsCarrying) DropNeutral();
    }

    private void Update()
    {
        // Agarrar é automático: segurar Interagir + encostar a um Carryable.
        if (!canGrab || IsCarrying) return;
        if (input == null || !input.InteractHeld) return;
        if (climb != null && climb.IsClimbing) return; // Interagir já está a segurar a superfície.
        if (swing != null && swing.IsSwinging) return; // a balançar num cipó (P8).

        TryGrab();
    }

    /// <summary>Soltar Interagir larga o objecto carregado (com física de momentum — ver Drop).</summary>
    private void HandleInteractReleased()
    {
        if (IsCarrying) Drop();
    }

    /// <summary>
    /// Procura um Carryable à frente do player (dentro de 'grabRange') que a
    /// forma consiga agarrar e levanta-o. Devolve true se agarrou.
    /// </summary>
    public bool TryGrab()
    {
        if (!canGrab || IsCarrying) return false;

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;
        Vector2 center = (Vector2)transform.position + new Vector2(dir * grabRange * 0.5f, 0f);

        int count = Physics2D.OverlapBoxNonAlloc(center, new Vector2(grabRange, 1f), 0f, _grabBuffer);

        for (int i = 0; i < count; i++)
        {
            var hit = _grabBuffer[i];
            var carryable = hit.GetComponent<Carryable>();
            if (carryable == null || carryable.IsCarried) continue;

            float weight = carryable.Weight;
            if (weight > maxCarryWeight) continue;

            PickUp(carryable);
            return true;
        }

        return false;
    }

    /// <summary>Atira (canThrow) ou larga o objecto carregado. Usado pelo botão de ATAQUE enquanto carrega.</summary>
    public void ThrowOrDrop()
    {
        if (!IsCarrying) return;

        if (canThrow) Throw();
        else Drop();
    }

    private void PickUp(Carryable carryable)
    {
        _carried = carryable;
        carryable.OnPickedUp(carryAnchor);
    }

    /// <summary>
    /// Larga o objecto carregado com física baseada no movimento do player
    /// nesse instante (chamado ao SOLTAR Interagir, ou como fallback do
    /// botão de Ataque em formas sem 'canThrow'):
    ///
    /// - A correr: o objecto fica com a velocidade actual do player ("física
    ///   normal", o momentum funciona como força de disparo). Se também
    ///   estiver a segurar para CIMA, soma um impulso vertical extra (sobe
    ///   mais).
    /// - Parado + a segurar para CIMA: o objecto é só jogado para cima (sem
    ///   deslocamento horizontal).
    /// - Parado sem input para cima: cai à frente do player, sem velocidade
    ///   (comportamento antigo).
    /// </summary>
    public void Drop()
    {
        if (!IsCarrying) return;

        Vector2 playerVel = motor.RB.linearVelocity;
        float upInput = input != null ? input.Move.y : 0f;
        bool pressingUp = upInput >= releaseUpThreshold;
        bool isRunning = Mathf.Abs(playerVel.x) >= runningSpeedThreshold;

        Vector2 dropPos;
        Vector2 velocity;

        if (isRunning)
        {
            // Física normal: herda o momentum do player (força de disparo).
            dropPos = carryAnchor.position;
            velocity = playerVel;
            if (pressingUp) velocity.y += releaseUpBoost;
        }
        else if (pressingUp)
        {
            // Parado + para cima: jogado só para cima.
            dropPos = carryAnchor.position;
            velocity = new Vector2(0f, verticalTossForce);
        }
        else
        {
            // Parado, sem input: pousa à frente, sem velocidade.
            int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;
            dropPos = (Vector2)transform.position + new Vector2(dir * 0.8f, 0.2f);
            velocity = Vector2.zero;
        }

        _carried.OnReleased(dropPos, velocity);
        _carried = null;
    }

    /// <summary>
    /// Larga o objecto carregado de forma NEUTRA: pousa à frente do player,
    /// sem herdar a velocidade do player nem qualquer impulso (ao contrário
    /// de <see cref="Drop"/>, nunca "arremessa"). Usado pelo cancelamento
    /// centralizado (<see cref="Cancel"/> — transformar, morrer, diálogo,
    /// armadilha, etc.) e por <see cref="ConfigureFromForm"/>, onde largar
    /// com o momentum do player a correr poderia atirar o objecto
    /// acidentalmente.
    /// </summary>
    public void DropNeutral()
    {
        if (!IsCarrying) return;

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;
        Vector2 dropPos = (Vector2)transform.position + new Vector2(dir * 0.8f, 0.2f);

        _carried.OnReleased(dropPos, Vector2.zero);
        _carried = null;
    }

    /// <summary>Atira o objecto na direcção do facing ("arremesso sem dano" — o objecto pode ter dano próprio, ex: EggObject).</summary>
    public void Throw()
    {
        if (!IsCarrying) return;

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;
        Vector2 velocity = new Vector2(dir * throwForce, throwUpForce);

        _carried.OnReleased(carryAnchor.position, velocity);
        _carried = null;
    }

    // ---- IAbility (item 8) ----
    // GrabThrow agarra/larga automaticamente via Interagir (Update/
    // HandleInteractReleased), não pelo botão de habilidade.
    void IAbility.Activate() { }
    void IAbility.Release() { }

    /// <summary>
    /// Larga o objecto carregado de forma neutra (ver DropNeutral — nunca
    /// herda velocidade/impulso). Cancelamento centralizado (transformar,
    /// morrer, diálogo, etc.) deve sempre largar de forma neutra, nunca
    /// arremessar.
    /// </summary>
    public void Cancel(AbilityCancelReason reason)
    {
        if (IsCarrying) DropNeutral();
    }

    public float CooldownRemaining => 0f;
    bool IAbility.IsActive => IsCarrying;

    // ---- IActiveAbility (Tarefa #34 — HUD) ----
    // Sem cooldown: a HUD não mostra indicador para esta habilidade. Agarra/
    // larga automaticamente via Interagir — CanActivate reflecte apenas se a
    // forma consegue agarrar e não está já a carregar algo.
    public float CooldownDuration => 0f;
    public bool CanActivate => canGrab && !IsCarrying;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }
}
